// ── Helper: safe table lookup ─────────────────────────────────────────────────

function _getEntry(table, ...keys) {
  let node = table;
  for (const k of keys) {
    if (!node || typeof node !== 'object') return null;
    node = node[k];
  }
  return (node && (node.standard || node.oracle)) ? node : null;
}

function _text(table, mode, ...keys) {
  const e = _getEntry(table, ...keys);
  return e ? (e[mode] || '') : '';
}

// ── Placement interpretation ──────────────────────────────────────────────────

function interpretPlacement(planetId, signName, houseNum, mode) {
  const signText  = _text(PLANET_IN_SIGN,  mode, planetId, signName);
  const houseText = _text(PLANET_IN_HOUSE, mode, planetId, String(houseNum));
  return [signText, houseText].filter(Boolean).join(' ');
}

// ── Transit interpretations ───────────────────────────────────────────────────

function interpretTopTransits(transitAspects, mode) {
  return transitAspects.slice(0, 3).map(t => {
    const text  = _text(TRANSIT_BY_PLANET, mode, t.transiting || t.bodyA, t.name);
    const house = t.natalHouse;
    const theme = house ? HOUSE_THEMES[house - 1] : '';
    const dir   = t.applying === true  ? (mode === 'oracle' ? ' The pressure is increasing.' : ' Applying — the peak is ahead.')
                : t.applying === false ? (mode === 'oracle' ? ' The peak has passed.' : ' Separating — the moment is integrating.')
                : '';
    return `**${t.transiting || t.bodyA} ${t.symbol} natal ${t.natal || t.bodyB}**${house ? ` (H${house} — ${theme})` : ''}: ${text}${dir}`;
  }).filter(Boolean);
}

// ── Full reading ──────────────────────────────────────────────────────────────

function buildFullReading(natalChart, currentChart, transitAspects, natalAspects,
                          dominantPlanet, dominantHouse, sunHouse, moonHouse, ascHouse, mode) {
  const sun  = natalChart.Sun;
  const moon = natalChart.Moon;
  const asc  = natalChart.Ascendant;
  const mc   = natalChart.MC;

  const identity   = sun  ? interpretPlacement('Sun',  sun.sign.name,  sunHouse  || 1, mode) : '';
  const emotion    = moon ? interpretPlacement('Moon', moon.sign.name, moonHouse || 1, mode) : '';
  const projection = asc  ? _text(PLANET_IN_SIGN, mode, 'Sun', asc.sign.name) : '';
  const vocation   = mc   ? _text(PLANET_IN_SIGN, mode, 'Sun', mc.sign.name)  : '';

  const transitLines = interpretTopTransits(transitAspects, mode);

  // Tight aspect oracle hint (puzzle layer 2)
  const tightAspects = (natalAspects || []).filter(a => a.orb < 0.5);
  const tightHint = (mode === 'standard' && tightAspects.length > 0)
    ? ' The precision of this alignment is not an approximation. The sky does not round to the nearest comfortable answer. Neither does the full reading.'
    : '';

  const synthesis = _buildSynthesis(sun, moon, dominantPlanet, dominantHouse, transitAspects, mode) + tightHint;

  // Permanent subtle footer hint (puzzle layer 3)
  const footerHint = mode === 'standard'
    ? 'This reading reflects one lens. Every lens has a field of view.'
    : '';

  return { identity, projection, vocation, emotion, transitLines, synthesis, footerHint };
}

function _buildSynthesis(sun, moon, dominantPlanet, dominantHouse, transitAspects, mode) {
  const sunSign  = sun?.sign?.name  || '';
  const moonSign = moon?.sign?.name || '';
  const domTheme = dominantHouse ? HOUSE_THEMES[dominantHouse - 1] : '';
  const top      = transitAspects?.[0];

  if (mode === 'standard') {
    const parts = [];
    if (sunSign && moonSign && sunSign !== moonSign) {
      parts.push(`The ${sunSign} solar identity and ${moonSign} lunar emotional patterning create a core tension that, navigated consciously, is your primary resource.`);
    } else if (sunSign) {
      parts.push(`The ${sunSign} solar and lunar principles are aligned — the self and the emotional body move together, which is a remarkable structural foundation.`);
    }
    if (dominantPlanet && domTheme) {
      parts.push(`${dominantPlanet} is currently the most active force in your chart — its influence is concentrated in the area of ${domTheme.toLowerCase()}.`);
    }
    if (top) {
      parts.push(`The most exact current influence is ${top.transiting || top.bodyA} ${top.symbol} your natal ${top.natal || top.bodyB} — this is the live edge of the moment.`);
    }
    return parts.join(' ');
  } else {
    const parts = [];
    if (sunSign && moonSign) {
      parts.push(`${sunSign} solar identity and ${moonSign} lunar patterning ${sunSign === moonSign ? 'operate in fusion — intense, coherent, and capable of both extraordinary focus and closed-loop self-reinforcement' : 'are structurally in tension — the conscious self and the emotional body want different things, and this conflict is the operating condition, not a temporary problem to be solved'}.`);
    }
    if (dominantPlanet && domTheme) {
      parts.push(`${dominantPlanet} is exerting maximum pressure on natal House ${dominantHouse} (${domTheme}). This is not symbolic. The mathematical weight is measurable and the effect is ongoing.`);
    }
    if (top) {
      parts.push(`${top.transiting || top.bodyA} is within ${top.orb.toFixed(1)}° of exact ${(top.name||'').toLowerCase()} to your natal ${top.natal || top.bodyB}. ${top.applying ? 'The pressure is increasing.' : 'The peak has passed; what it revealed remains.'}`);
    }
    return parts.join(' ');
  }
}

// ── Synastry reading ──────────────────────────────────────────────────────────

function buildSynastryReading(chartA, chartB, crossAspects, mode) {
  const venusMars = crossAspects.find(a =>
    (a.bodyA === 'Venus' && a.bodyB === 'Mars') ||
    (a.bodyA === 'Mars'  && a.bodyB === 'Venus'));
  const sunSun  = crossAspects.find(a => a.bodyA === 'Sun' && a.bodyB === 'Sun');
  const moonMoon = crossAspects.find(a => a.bodyA === 'Moon' && a.bodyB === 'Moon');

  const attraction = venusMars
    ? _text(SYNASTRY_ASPECTS, mode, 'VenusMars', venusMars.name) ||
      (mode === 'standard'
        ? 'Significant Venus-Mars contact. The chemistry is in the chart.'
        : `Venus-Mars ${venusMars.name.toLowerCase()} at ${venusMars.orb.toFixed(1)}° orb. The desire function is structurally engaged.`)
    : (mode === 'standard'
        ? 'No direct Venus-Mars contact within orb. Attraction operates through other channels.'
        : 'No Venus-Mars contact in primary orb. Physical attraction is not the primary structural driver of this connection.');

  const frictionAspects = crossAspects.filter(a => ['Square', 'Opposition'].includes(a.name)).slice(0, 2);
  const friction = frictionAspects.length
    ? frictionAspects.map(a => `${a.bodyA} ${a.symbol} ${a.bodyB} (${a.orb.toFixed(1)}°)`).join(', ')
    : (mode === 'standard' ? 'Minimal hard aspect friction in the cross-chart.' : 'Low cross-chart hard aspect density. Friction, when it appears, will come from within each individual chart rather than the interface between them.');

  const longTerm = sunSun
    ? _text(SYNASTRY_ASPECTS, mode, 'SunSun', sunSun.name) || ''
    : (mode === 'standard'
        ? 'Sun signs do not aspect directly. Shared direction must be consciously built — it is not structural.'
        : 'No Sun-Sun aspect. The core identities do not have a direct structural relationship; the coherence of the partnership depends on choice rather than geometric compatibility.');

  const top = crossAspects[0];
  const synthesis = top
    ? (mode === 'standard'
        ? `The strongest link between these charts is ${top.bodyA} ${top.symbol} ${top.bodyB} at ${top.orb.toFixed(1)}°. This is the axis the relationship turns on.`
        : `The dominant structural link is ${top.bodyA} ${top.name.toLowerCase()} ${top.bodyB} at ${top.orb.toFixed(1)}° orb. The relationship is organized around this geometry whether either person is aware of it or not.`)
    : (mode === 'standard'
        ? 'These charts are loosely coupled — the relationship is built by choice rather than by structural pull.'
        : 'Weak cross-chart aspect density. This relationship is not driven by compulsive geometry; what it becomes is entirely a product of what both people choose to build.');

  const moonEmotional = moonMoon
    ? _text(SYNASTRY_ASPECTS, mode, 'MoonMoon', moonMoon.name) || ''
    : '';

  return { attraction, friction, longTerm, moonEmotional, synthesis };
}
